fun solve(nums: Array<Long>, queries: Array<Array<Long>>): Long {
    val MOD = 1000000007
    val n = nums.size
    val res = LongArray(n)
    for (i in 0 until n) {
        res[i] = nums[i]
    }

    for (query in queries) {
        val li = query[0].toInt()
        val ri = query[1].toInt()
        val ki = query[2].toInt()
        val vi = query[3].toInt()

        var idx = li
        while (idx <= ri) {
            res[idx] = (res[idx] * vi) % MOD
            idx += ki
        }
    }

    var xorResult = 0L
    for (num in res) {
        xorResult = xorResult xor num
    }
    return xorResult
}
